func TestHelpExecutedOnNonRunnableChild(t *testing.T) {
	rootCmd := &Command{Use: "root", Run: emptyRun}
	childCmd := &Command{Use: "child", Long: "Long description"}
	rootCmd.AddCommand(childCmd)

	_, err := executeCommand(rootCmd, "child")
	if err == nil {
		t.Fatal("Expected error for non-runnable child with no subcommands")
	}

	expected := `command "child" is not runnable`
	if !strings.Contains(err.Error(), expected) {
		t.Errorf("Expected error containing %q, got: %v", expected, err)
	}
}

func TestNonRunnableLeafCommandReturnsError(t *testing.T) {
	rootCmd := &Command{Use: "root", Run: emptyRun}
	leafCmd := &Command{Use: "leaf"}
	rootCmd.AddCommand(leafCmd)

	_, err := executeCommand(rootCmd, "leaf")
	if err == nil {
		t.Fatal("Expected error for non-runnable leaf command")
	}

	expected := `command "leaf" is not runnable`
	if !strings.Contains(err.Error(), expected) {
		t.Errorf("Expected error containing %q, got: %v", expected, err)
	}
}

func TestNonRunnableParentWithSubcommandsShowsHelp(t *testing.T) {
	rootCmd := &Command{Use: "root", Run: emptyRun}
	parentCmd := &Command{Use: "parent", Long: "Parent long description"}
	childCmd := &Command{Use: "child", Run: emptyRun}
	parentCmd.AddCommand(childCmd)
	rootCmd.AddCommand(parentCmd)

	output, err := executeCommand(rootCmd, "parent")
	if err != nil {
		t.Errorf("Unexpected error: %v", err)
	}

	checkStringContains(t, output, parentCmd.Long)
}
